// // This module increments the counter value by one on each rising edge of the clock signal 'clk'. The counter has an asynchronous reset 'rst' that resets the counter to its minimum value when asserted.
module down_counter(
    input clk,
    input rst,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (rst)
            count <= 4'b1111;
        else
            count <= count - 1;
    end

endmodule
